const response = $json;
const now = new Date().toISOString();
const sellerId = 'REPLACE_WITH_SELLER_ID';
const marketplace = 'jumia';
const orders = Array.isArray(response.orders) ? response.orders : [];
function valueOrFallback(value, fallback = '') {
  return value === undefined || value === null || value === '' ? fallback : value;
}
function toNumber(value) {
  const number = Number(valueOrFallback(value, 0));
  return Number.isFinite(number) ? number : 0;
}
function toBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return value.toLowerCase() === 'true';
  return Boolean(value);
}
function buildCustomerName(address = {}) {
  return [address.firstName, address.lastName].filter(Boolean).join(' ') || 'Unknown customer';
}
function buildShippingAddress(address = {}) {
  return [address.address, address.ward, address.city, address.region, address.postalCode, address.countryName].filter(Boolean).join(', ');
}
function normalizeOrder(order) {
  const orderId = String(valueOrFallback(order.number, order.id)).trim();
  if (!orderId) return null;
  const amount = order.totalAmountLocal || order.totalAmount || {};
  const country = order.country || {};
  const shipping = order.shippingAddress || {};
  return {
    seller_id: sellerId,
    marketplace,
    event_type: 'ORDER_CREATED',
    received_at: now,
    order_id: orderId,
    jumia_order_id: order.id || '',
    order: {
      order_id: orderId,
      jumia_order_id: order.id || '',
      shop_ids: Array.isArray(order.shopIds) ? order.shopIds.join(', ') : '',
      date: valueOrFallback(order.createdAt, now),
      updated_at: valueOrFallback(order.updatedAt, ''),
      pending_since: valueOrFallback(order.pendingSince, ''),
      status: valueOrFallback(order.status, 'unknown'),
      delivery_option: valueOrFallback(order.deliveryOption, ''),
      total_items: toNumber(order.totalItems),
      packed_items: toNumber(order.packedItems),
      is_prepayment: toBoolean(order.isPrepayment),
      has_multiple_status: toBoolean(order.hasMultipleStatus),
      has_items_fulfilled_by_jumia: toBoolean(order.hasItemsFulfilledByJumia),
      customer_name: buildCustomerName(shipping),
      total: toNumber(amount.value),
      currency: valueOrFallback(amount.currency, country.currencyCode || 'NGN'),
      country_code: valueOrFallback(country.code, ''),
      country_name: valueOrFallback(country.name, ''),
      shipping_city: valueOrFallback(shipping.city, ''),
      shipping_region: valueOrFallback(shipping.region, ''),
      shipping_address: buildShippingAddress(shipping)
    },
    raw_order: order
  };
}
return orders.map(normalizeOrder).filter(Boolean).map(order => ({ json: order }));

const ctx = $json;
const order = ctx.order;
function formatMoney(value, currency) {
  try {
    return new Intl.NumberFormat('en', { style: 'currency', currency, maximumFractionDigits: 0 }).format(Number(value || 0));
  } catch (error) {
    return String(value || 0) + ' ' + String(currency || '').trim();
  }
}
const message = [
  'New Jumia Order',
  '',
  'Order: ' + order.order_id,
  'Status: ' + order.status,
  'Date: ' + order.date,
  'Pending Since: ' + (order.pending_since || 'Not supplied'),
  'Delivery: ' + (order.delivery_option || 'Not supplied'),
  'Customer: ' + order.customer_name,
  'Total: ' + formatMoney(order.total, order.currency),
  'Items: ' + order.total_items,
  'Packed Items: ' + order.packed_items,
  'Prepayment: ' + (order.is_prepayment ? 'Yes' : 'No'),
  'Fulfilled by Jumia: ' + (order.has_items_fulfilled_by_jumia ? 'Yes' : 'No'),
  '',
  'Shipping City: ' + (order.shipping_city || 'Not supplied'),
  'Shipping Address: ' + (order.shipping_address || 'Not supplied'),
  '',
  'Please prepare this order for fulfillment.'
].join('\n');
return [{ json: { ...ctx, notification_message: message, processed_at: new Date().toISOString() } }];
